                          <text x={mL+pS+Math.max(lw,2)/2} y={y+h/2} textAnchor="middle" dominantBaseline="middle" fill="#8ab" fontSize={Math.min(h*0.55,13)} fontFamily="DM Mono,monospace" fontWeight={500}>{lr.text}</text>
