                    <span title={`MaximГЎlnГӯ vГҪЕЎka ЕҷГЎdku nad ГәДҚaЕҷГӯm (vДҚetnДӣ diakritiky): ${lr.maxAbove} mm`} style={{fontFamily:"'DM Mono',monospace",fontSize:11,color:lr.maxAbove>height?"#e8a050":"#555",cursor:"help"}}>вҶ‘{lr.maxAbove}</span>
                    {lr.maxBelow>0&&<span title={`MaximГЎlnГӯ hloubka descenderЕҜ pod ГәДҚaЕҷГӯm: ${lr.maxBelow} mm`} style={{fontFamily:"'DM Mono',monospace",fontSize:11,color:"#7090c0",cursor:"help"}}>вҶ“{lr.maxBelow}</span>}
